class Solution {
public:
int minCoins(int amount, vector<int>& coins) {
	int dp[amount + 1];
	dp[0] = 0;
	for (int i = 1; i <= amount; i++) {
		for (int coin : coins) {
			if (coin <= i) {
				if (dp[i - coin] + 1 < dp[i]) {
					dp[i] = dp[i - coin] + 1;
				}
			}
		}
	}
	return dp[amount] == amount + 1 ? -1 : dp[amount];
}
};
